INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('GM_CONTENT: Le pillar-cluster-spoke model: 1 pilier (3000 mots) → 10 clusters (1500 mots) → 30 spokes (500 mots social). 41 contenus lies = domination SEO.', 'Pillar-cluster-spoke: 1 pilier + 10 clusters + 30 spokes = 41 contenus SEO', 'content', 'best_practice', 0.88, 'grandmaster', 'system'),
('GM_CONTENT: Le engagement rate formula: (likes + comments + shares + saves) / reach × 100. Benchmark: 1-3% bon, 3-6% tres bon, >6% viral.', 'Engagement rate: (likes+comments+shares+saves)/reach. 1-3% bon, >6% viral', 'content', 'insight', 0.88, 'grandmaster', 'system'),
('GM_CONTENT: Le content performance matrix: classer chaque contenu par effort (faible/moyen/eleve) × impact (faible/moyen/eleve). Focus sur faible effort + haut impact.', 'Content matrix: effort × impact. Focus low effort + high impact', 'content', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_CONTENT: Le algorithmic amplification: les 60 premieres minutes post-publication determinent 80% de la portee. Mobiliser l engagement immediat.', 'Algo amplification: 60 premieres minutes = 80% portee. Engagement immediat', 'content', 'insight', 0.88, 'grandmaster', 'system'),
('GM_CONTENT: Le content diversification ratio: 40% educatif, 25% divertissant, 20% inspirant, 10% communautaire, 5% promotionnel. Jamais >10% promo.', 'Content ratio: 40% edu + 25% fun + 20% inspi + 10% communaute + 5% promo. Max 10% promo', 'content', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_COMMERCIAL: Le consultative selling depth: poser 5 questions avant de presenter quoi que ce soit. Le prospect qui parle plus se sent ecoute et achete plus.', 'Consultative: 5 questions avant presenter. Prospect parle = ecoute = achete', 'commercial', 'best_practice', 0.88, 'grandmaster', 'system'),
('GM_COMMERCIAL: Le proof stack: temoignage texte + temoignage video + case study + chiffres ROI + logos clients + awards. Plus de preuves = plus de confiance.', 'Proof stack: texte + video + case study + ROI + logos + awards = max confiance', 'commercial', 'best_practice', 0.88, 'grandmaster', 'system'),
('GM_COMMERCIAL: Le pipeline hygiene weekly: chaque vendredi, deplacer les deals stagnants (>14j sans activite) en lost ou re-qualifier. Pipeline propre = forecast fiable.', 'Pipeline hygiene vendredi: >14j stagnant → lost ou re-qualifier', 'commercial', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_COMMERCIAL: Le value-based closing: ne jamais demander "voulez-vous acheter?" mais "base sur les resultats qu on a discute, quelle serait la prochaine etape logique?"', 'Value closing: prochaine etape logique? Pas voulez-vous acheter?', 'commercial', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_COMMERCIAL: Le customer reference program: constituer une bibliotheque de 20+ clients prets a etre contactes par les prospects. Segmenter par industrie/taille.', 'Reference program: 20+ clients disponibles segmentes industrie/taille', 'commercial', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_EMAIL: Le email architecture: transactional (confirm, facture) → lifecycle (onboarding, retention) → campaign (promo, contenu) → triggered (comportement). 4 piliers.', 'Email architecture: transactional + lifecycle + campaign + triggered = 4 piliers', 'email', 'best_practice', 0.88, 'grandmaster', 'system'),
('GM_EMAIL: Le cohort email analysis: mesurer OR/CTR/conversion par cohorte d inscription (semaine 1, 2, 3...) pour detecter si l engagement decline avec le temps.', 'Cohort email: OR/CTR/conv par cohorte inscription = detecter decline engagement', 'email', 'best_practice', 0.82, 'grandmaster', 'system'),
('GM_EMAIL: Le revenue per email (RPE) est LA metrique ultime: revenu total genere / nombre total d emails envoyes. Optimiser le RPE pas juste l OR.', 'RPE = revenu/emails envoyes. Optimiser RPE pas juste OR', 'email', 'insight', 0.85, 'grandmaster', 'system'),
('GM_EMAIL: Le predictive send optimization: utiliser l historique d ouverture de chaque contact pour predire SA meilleure heure. Augmente OR de 15%.', 'Predictive send: historique ouverture → predire meilleure heure = +15% OR', 'email', 'best_practice', 0.82, 'grandmaster', 'system'),
('GM_SEO: Le authority building systematic: 1 guest post/mois sur un site DR>50 + 2 infographies/trimestre + 1 etude originale/an = backlinks naturels continus.', 'Authority building: 1 guest post/mois DR50 + 2 infographies/trim + 1 etude/an', 'seo', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_SEO: Le technical SEO priority: 1) indexation correcte, 2) vitesse < 2s, 3) mobile-first, 4) structured data, 5) canonical/hreflang, 6) internal linking.', 'Tech SEO priority: indexation → vitesse → mobile → schema → canonical → internal links', 'seo', 'best_practice', 0.88, 'grandmaster', 'system'),
('GM_SEO: Le content decay detection: surveiller mensuellement les articles qui perdent du ranking (position +5 sur 30j). Mettre a jour en priorite.', 'Content decay: articles perdant position +5/30j = MAJ prioritaire', 'seo', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_SEO: Le zero-click optimization: pour les requetes ou Google repond directement, optimiser pour la visibilite (featured snippet, knowledge panel) pas le clic.', 'Zero-click: optimiser visibilite snippet/panel pas clic', 'seo', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_ADS: Le creative production system: 1 shooting day/mois → 10 raw clips → 30 edited creatives → 5 gagnantes → scale les gagnantes → repeat.', 'Creative production: 1 shooting → 10 clips → 30 edits → 5 gagnantes → scale', 'ads', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_ADS: Le incrementality testing: couper les ads dans une geo (test) et comparer les ventes vs une geo avec ads (control). Mesure le vrai impact incremental.', 'Incrementality: couper ads 1 geo, comparer vs geo avec ads = vrai impact', 'ads', 'best_practice', 0.82, 'grandmaster', 'system'),
('GM_ADS: Le budget optimization algorithm: si ROAS > 2x cible → +30% budget. Si ROAS > cible → +15%. Si ROAS < cible 3j → -20%. Si < breakeven → pause.', 'Budget algo: >2x cible +30%, >cible +15%, <cible 3j -20%, <breakeven pause', 'ads', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_ADS: Le landing page match: chaque ad doit mener a une landing page qui reprend le MEME message, la MEME image, le MEME CTA. Coherence = conversion.', 'Landing page match: meme message+image+CTA que l ad = coherence = conversion', 'ads', 'best_practice', 0.88, 'grandmaster', 'system'),
('GM_CEO: Le north star metric cascade: north star (actions agents reussies) → sub-metrics par agent → leading indicators → actionable metrics.', 'North star cascade: NSM → sub-metrics/agent → leading → actionable', 'ceo', 'best_practice', 0.90, 'grandmaster', 'system'),
('GM_CEO: Le weekly growth sprint: lundi priorites, mardi-jeudi execution, vendredi review + planning semaine+1. Cadence reguliere = progres constant.', 'Weekly sprint: lundi priorities, mar-jeu execution, ven review. Cadence = progres', 'ceo', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_CEO: Le build-measure-learn velocity: l objectif n est pas de construire plus vite mais d APPRENDRE plus vite. 1 experiment/semaine minimum.', 'Build-measure-learn: apprendre vite > construire vite. 1 experiment/semaine min', 'ceo', 'best_practice', 0.88, 'grandmaster', 'system'),
('GM_RETENTION: Le customer success score composite: product usage (30%) + feature adoption (20%) + support health (15%) + NPS (15%) + payment (10%) + engagement (10%).', 'CS score: usage 30% + features 20% + support 15% + NPS 15% + payment 10% + engagement 10%', 'retention', 'best_practice', 0.88, 'grandmaster', 'system'),
('GM_RETENTION: Le renewal playbook: 90j avant → value recap, 60j → success review, 30j → renewal proposal, 14j → negotiation, 7j → signature, J0 → renouvele.', 'Renewal: 90j recap → 60j review → 30j proposal → 14j nego → 7j sign → J0 done', 'retention', 'best_practice', 0.85, 'grandmaster', 'system'),
('GM_ONBOARDING: Le activation funnel: signup → email verified → profile complete → first action → second action → aha moment → habit formed. Mesurer chaque etape.', 'Activation funnel: signup → verify → profile → 1st action → 2nd → aha → habit', 'onboarding', 'best_practice', 0.88, 'grandmaster', 'system'),
('GM_CROSS: Le intelligence network: chaque agent est a la fois producteur et consommateur de data. Le CEO orchestre les flux. Le RAG memorise tout.', 'Intelligence network: agents producteurs+consommateurs. CEO orchestre. RAG memorise', NULL, 'best_practice', 0.92, 'grandmaster', 'system'),
('GM_CROSS: Le real-time optimization loop: detecter signal → analyser → decider → executer → mesurer → apprendre → ameliorer. Cycle < 24h pour les agents IA.', 'Optimization loop: signal → analyse → decision → execution → mesure → learn → improve. < 24h', NULL, 'best_practice', 0.90, 'grandmaster', 'system')
